/**
 * GET /admin/drafts — list drafts (empty path).
 * GET /admin/drafts/{slug} — preview + edit (single path segment).
 */
import { adminShell } from "../_admin-ui.js";

function htmlList() {
  const main = `
<header class="top">
  <h1>Draft posts</h1>
  <button type="button" class="btn btn-primary" id="publishAll">Publish all approved</button>
  <a class="btn" href="/">Home</a>
</header>
<div id="msg" class="msg" role="status"></div>
<div class="card table-wrap">
  <p id="loading">Loading drafts…</p>
  <table id="tbl" style="display:none">
    <thead>
      <tr>
        <th>Title</th>
        <th>Slug</th>
        <th>Status</th>
        <th>Category</th>
        <th>Updated</th>
        <th></th>
      </tr>
    </thead>
    <tbody id="tbody"></tbody>
  </table>
</div>`;

  const script = `
function showMsg(text, isErr) {
  var el = document.getElementById("msg");
  el.textContent = text;
  el.className = "msg show " + (isErr ? "err" : "ok");
}
async function load() {
  var loading = document.getElementById("loading");
  var tbl = document.getElementById("tbl");
  var tbody = document.getElementById("tbody");
  try {
    var r = await fetch("/api/drafts");
    var data = await r.json();
    if (!r.ok) throw new Error(data.error || r.statusText);
    loading.style.display = "none";
    tbl.style.display = "table";
    tbody.innerHTML = "";
    var items = Array.isArray(data.items) ? data.items : [];
    items.forEach(function (row) {
      if (!row || !row.slug) return;
      var tr = document.createElement("tr");
      var slugEnc = encodeURIComponent(row.slug);
      tr.innerHTML =
        "<td>" + escapeHtml(String(row.title || "")) + "</td>" +
        "<td class=\\"slug\\"><a href=\\"/admin/drafts/" + slugEnc + "\\">" + escapeHtml(String(row.slug)) + "</a></td>" +
        "<td>" + escapeHtml(String(row.status || "")) + "</td>" +
        "<td>" + escapeHtml(String(row.category || "")) + "</td>" +
        "<td>" + escapeHtml(String(row.updatedDate || "")) + "</td>" +
        "<td><button type=\\"button\\" class=\\"btn btn-primary approve\\" data-slug=\\"" + escapeAttr(row.slug) + "\\">Approve</button></td>";
      tbody.appendChild(tr);
    });
    if (!items.length) tbody.innerHTML = "<tr><td colspan=6>No drafts in KV.</td></tr>";
  } catch (e) {
    loading.textContent = "Failed to load: " + (e && e.message ? e.message : e);
  }
}
function escapeHtml(s) {
  return String(s).replace(/&/g,"&amp;").replace(/</g,"&lt;").replace(/>/g,"&gt;").replace(/"/g,"&quot;");
}
function escapeAttr(s) {
  return String(s).replace(/&/g,"&amp;").replace(/"/g,"&quot;");
}
document.getElementById("publishAll").addEventListener("click", async function () {
  try {
    var r = await fetch("/api/publish-now", { method: "POST", headers: { "Content-Type": "application/json" }, body: "{}" });
    var j = await r.json();
    if (!r.ok || !j.ok) throw new Error(j.error || r.statusText);
    showMsg("Published " + (j.published|0) + " post(s).", false);
    load();
  } catch (e) {
    showMsg("Publish failed: " + (e && e.message ? e.message : e), true);
  }
});
document.getElementById("tbody").addEventListener("click", async function (ev) {
  var btn = ev.target.closest(".approve");
  if (!btn) return;
  var slug = btn.getAttribute("data-slug");
  if (!slug) return;
  btn.disabled = true;
  try {
    var r = await fetch("/api/approve", { method: "POST", headers: { "Content-Type": "application/json" }, body: JSON.stringify({ slug: slug }) });
    var j = await r.json();
    if (!r.ok || !j.ok) throw new Error(j.error || r.statusText);
    showMsg("Approved: " + slug, false);
    load();
  } catch (e) {
    showMsg("Approve failed: " + (e && e.message ? e.message : e), true);
  } finally {
    btn.disabled = false;
  }
});
load();
`;

  return new Response(adminShell("Drafts · Admin", main, script), {
    headers: {
      "Content-Type": "text/html; charset=utf-8",
      "Cache-Control": "no-store"
    }
  });
}

function htmlDetail(slug) {
  const slugJson = JSON.stringify(slug);

  const main = `
<header class="top">
  <h1>Draft preview</h1>
  <a class="btn" href="/admin/drafts">← All drafts</a>
  <a class="btn" href="/">Home</a>
</header>
<div id="msg" class="msg" role="status"></div>
<div class="card" id="panel" style="display:none">
  <p class="slug">Slug: <strong id="slugLabel"></strong> · <span id="meta"></span></p>
  <div class="actions">
    <button type="button" class="btn btn-primary" id="btnApprove">Approve</button>
    <button type="button" class="btn btn-primary" id="btnSave">Save draft</button>
  </div>
  <label for="fTitle">Title</label>
  <input type="text" id="fTitle" autocomplete="off" />
  <label for="fExcerpt">Excerpt</label>
  <textarea id="fExcerpt" rows="3"></textarea>
  <label for="fMd">body_markdown</label>
  <textarea id="fMd" class="md"></textarea>
  <h2 style="margin-top:1.25rem;font-size:1rem">Preview</h2>
  <div class="preview-body article-body" id="preview"></div>
</div>
<p id="loading">Loading…</p>`;

  const script = `
var SLUG = ${slugJson};
function showMsg(text, isErr) {
  var el = document.getElementById("msg");
  el.textContent = text;
  el.className = "msg show " + (isErr ? "err" : "ok");
}
var previewTimer = null;
async function refreshPreview() {
  var md = document.getElementById("fMd").value;
  try {
    var r = await fetch("/api/draft-preview-html", {
      method: "POST",
      headers: { "Content-Type": "application/json" },
      body: JSON.stringify({ body_markdown: md })
    });
    var j = await r.json();
    if (!r.ok || !j.ok) throw new Error(j.error || "preview failed");
    document.getElementById("preview").innerHTML = j.html || "";
  } catch (e) {
    document.getElementById("preview").textContent = "Preview error: " + (e && e.message ? e.message : e);
  }
}
function schedulePreview() {
  clearTimeout(previewTimer);
  previewTimer = setTimeout(refreshPreview, 400);
}
async function load() {
  var loading = document.getElementById("loading");
  try {
    var r = await fetch("/api/draft?slug=" + encodeURIComponent(SLUG));
    var data = await r.json();
    if (!r.ok) throw new Error(data.error || r.statusText);
    var it = data.item;
    loading.style.display = "none";
    document.getElementById("panel").style.display = "block";
    document.getElementById("slugLabel").textContent = it.slug || SLUG;
    document.getElementById("meta").textContent =
      (it.status || "") + " · " + (it.category || "") + " · " + (it.updatedDate || "");
    document.getElementById("fTitle").value = it.title || "";
    document.getElementById("fExcerpt").value = it.excerpt || "";
    document.getElementById("fMd").value = it.body_markdown || "";
    document.getElementById("preview").innerHTML = data.bodyHtml || "";
    document.getElementById("fMd").addEventListener("input", schedulePreview);
  } catch (e) {
    loading.textContent = "Failed: " + (e && e.message ? e.message : e);
  }
}
document.getElementById("btnSave").addEventListener("click", async function () {
  var btn = this;
  btn.disabled = true;
  try {
    var r = await fetch("/api/draft-save", {
      method: "POST",
      headers: { "Content-Type": "application/json" },
      body: JSON.stringify({
        slug: SLUG,
        title: document.getElementById("fTitle").value,
        excerpt: document.getElementById("fExcerpt").value,
        body_markdown: document.getElementById("fMd").value
      })
    });
    var j = await r.json();
    if (!r.ok || !j.ok) throw new Error(j.error || r.statusText);
    showMsg("Saved.", false);
    await refreshPreview();
  } catch (e) {
    showMsg("Save failed: " + (e && e.message ? e.message : e), true);
  } finally {
    btn.disabled = false;
  }
});
document.getElementById("btnApprove").addEventListener("click", async function () {
  var btn = this;
  btn.disabled = true;
  try {
    var r = await fetch("/api/approve", {
      method: "POST",
      headers: { "Content-Type": "application/json" },
      body: JSON.stringify({ slug: SLUG })
    });
    var j = await r.json();
    if (!r.ok || !j.ok) throw new Error(j.error || r.statusText);
    showMsg("Approved.", false);
    load();
  } catch (e) {
    showMsg("Approve failed: " + (e && e.message ? e.message : e), true);
  } finally {
    btn.disabled = false;
  }
});
load();
`;

  return new Response(adminShell("Draft · " + slug, main, script), {
    headers: {
      "Content-Type": "text/html; charset=utf-8",
      "Cache-Control": "no-store"
    }
  });
}

export async function onRequestGet(context) {
  let raw = (context.params && context.params.path) || "";
  if (Array.isArray(raw)) raw = raw.join("/");
  const path = String(raw).replace(/^\/+|\/+$/g, "");
  if (!path) {
    return htmlList();
  }
  const segments = path.split("/").filter(Boolean);
  if (segments.length !== 1) {
    return new Response("Not found", { status: 404 });
  }
  const slug = segments[0].trim();
  if (!slug) {
    return htmlList();
  }
  return htmlDetail(slug);
}
