/**
 * POST /api/draft-preview-html — body { body_markdown } returns { html } (admin live preview).
 */
import { bodyMarkdownToHtml } from "./_lib/blog-article-html.js";

function json(data, status, origin) {
  const o = origin || "*";
  return new Response(JSON.stringify(data), {
    status: status || 200,
    headers: {
      "Content-Type": "application/json",
      "Access-Control-Allow-Origin": o,
      "Access-Control-Allow-Methods": "POST, OPTIONS",
      "Access-Control-Allow-Headers": "Content-Type"
    }
  });
}

export async function onRequestOptions(context) {
  const origin = context.request.headers.get("Origin") || "*";
  return new Response(null, {
    status: 204,
    headers: {
      "Access-Control-Allow-Origin": origin,
      "Access-Control-Allow-Methods": "POST, OPTIONS",
      "Access-Control-Allow-Headers": "Content-Type"
    }
  });
}

export async function onRequestPost(context) {
  const { request } = context;
  const origin = request.headers.get("Origin") || "*";

  let body = {};
  try {
    const t = await request.text();
    body = t ? JSON.parse(t) : {};
  } catch {
    return json({ ok: false, error: "invalid_json" }, 400, origin);
  }
  const md = typeof body.body_markdown === "string" ? body.body_markdown : "";
  const html = bodyMarkdownToHtml(md);
  return json({ ok: true, html }, 200, origin);
}
