/** Shared inline CSS + small helpers for admin HTML responses. */

export const ADMIN_CSS = `
:root { font-family: system-ui, -apple-system, Segoe UI, Roboto, sans-serif; color: #1a1a1a; }
* { box-sizing: border-box; }
body { margin: 0; padding: 0.75rem 1rem 2rem; background: #f4f5f7; line-height: 1.45; font-size: 15px; }
header.top { display: flex; flex-wrap: wrap; align-items: center; gap: 0.5rem 1rem; margin-bottom: 1rem; }
header.top h1 { font-size: 1.15rem; margin: 0; flex: 1 1 auto; }
a { color: #0b5; }
.btn {
  display: inline-block; padding: 0.45rem 0.85rem; border-radius: 6px; border: 1px solid #ccc;
  background: #fff; cursor: pointer; font-size: 0.9rem; text-decoration: none; color: #222;
}
.btn:hover { background: #eee; }
.btn-primary { background: #0a7; color: #fff; border-color: #086; }
.btn-primary:hover { background: #086; }
.btn-danger { border-color: #c33; color: #a11; }
.msg { padding: 0.5rem 0.75rem; border-radius: 6px; margin: 0.5rem 0; font-size: 0.9rem; display: none; }
.msg.show { display: block; }
.msg.ok { background: #dfe; border: 1px solid #8c8; }
.msg.err { background: #fee; border: 1px solid #c88; }
.card { background: #fff; border-radius: 8px; padding: 1rem; box-shadow: 0 1px 3px rgba(0,0,0,.08); margin-bottom: 1rem; }
.table-wrap { overflow-x: auto; -webkit-overflow-scrolling: touch; }
table { width: 100%; border-collapse: collapse; font-size: 0.88rem; }
th, td { text-align: left; padding: 0.5rem 0.4rem; border-bottom: 1px solid #e5e5e5; vertical-align: top; }
th { font-weight: 600; background: #fafafa; }
tr:hover td { background: #fafafa; }
.slug { font-family: ui-monospace, monospace; font-size: 0.82rem; word-break: break-all; }
label { display: block; font-weight: 600; margin: 0.75rem 0 0.25rem; font-size: 0.88rem; }
input[type=text], textarea {
  width: 100%; max-width: 100%; padding: 0.5rem; border: 1px solid #ccc; border-radius: 6px; font: inherit;
}
textarea { min-height: 140px; resize: vertical; }
textarea.md { min-height: 220px; font-family: ui-monospace, monospace; font-size: 0.85rem; }
.preview-body { border: 1px solid #ddd; border-radius: 6px; padding: 1rem; background: #fff; }
.preview-body h2 { font-size: 1.1rem; margin: 1rem 0 0.5rem; }
.preview-body h3 { font-size: 1rem; margin: 0.85rem 0 0.4rem; }
.preview-body p { margin: 0.5rem 0; }
.actions { display: flex; flex-wrap: wrap; gap: 0.5rem; margin-top: 0.75rem; }
@media (min-width: 640px) {
  body { padding: 1rem 1.5rem 2.5rem; max-width: 1100px; margin: 0 auto; }
}
`;

export function adminShell(title, mainHtml, script) {
  return `<!DOCTYPE html>
<html lang="en">
<head>
  <meta charset="utf-8" />
  <meta name="viewport" content="width=device-width, initial-scale=1" />
  <title>${title}</title>
  <style>${ADMIN_CSS}</style>
</head>
<body>
${mainHtml}
<script>
${script}
</script>
</body>
</html>`;
}
