/** KV helpers for `drafts:pending-seo-pages` (read-only / write patterns aligned with publish-now). */

export const K_DRAFTS = "drafts:pending-seo-pages";

export async function readDraftsDoc(env, request) {
  const raw = await env.SEO_KV.get(K_DRAFTS);
  if (raw) {
    try {
      return JSON.parse(raw);
    } catch {
      return { version: 1, items: [] };
    }
  }
  const r = await env.ASSETS.fetch(new URL("/drafts/pending-seo-pages.json", request.url));
  if (!r.ok) return { version: 1, items: [] };
  const doc = JSON.parse(await r.text());
  await env.SEO_KV.put(K_DRAFTS, JSON.stringify(doc));
  return doc;
}

export async function writeDraftsDoc(env, doc) {
  await env.SEO_KV.put(K_DRAFTS, JSON.stringify(doc));
}
