/**
 * POST /api/approve — body { slug } sets draft status to "approved" in KV.
 */
import { readDraftsDoc, writeDraftsDoc } from "./_lib/drafts-kv.js";
import { normSlug, normalizeDraftStatus } from "./_lib/blog-article-html.js";

function json(data, status, origin) {
  const o = origin || "*";
  return new Response(JSON.stringify(data), {
    status: status || 200,
    headers: {
      "Content-Type": "application/json",
      "Access-Control-Allow-Origin": o,
      "Access-Control-Allow-Methods": "POST, OPTIONS",
      "Access-Control-Allow-Headers": "Content-Type"
    }
  });
}

export async function onRequestOptions(context) {
  const origin = context.request.headers.get("Origin") || "*";
  return new Response(null, {
    status: 204,
    headers: {
      "Access-Control-Allow-Origin": origin,
      "Access-Control-Allow-Methods": "POST, OPTIONS",
      "Access-Control-Allow-Headers": "Content-Type"
    }
  });
}

export async function onRequestPost(context) {
  const { request, env } = context;
  const origin = request.headers.get("Origin") || "*";

  if (!env.SEO_KV) {
    return json({ ok: false, error: "kv_not_configured" }, 503, origin);
  }

  let body = {};
  try {
    const t = await request.text();
    body = t ? JSON.parse(t) : {};
  } catch {
    return json({ ok: false, error: "invalid_json" }, 400, origin);
  }
  if (body === null || typeof body !== "object" || Array.isArray(body)) {
    return json({ ok: false, error: "body must be object" }, 400, origin);
  }

  const slug = normSlug({ slug: body.slug || "" });
  if (!slug) {
    return json({ ok: false, error: "slug required" }, 400, origin);
  }

  const doc = await readDraftsDoc(env, request);
  if (!Array.isArray(doc.items)) doc.items = [];

  const it = doc.items.find((i) => i && normSlug(i) === slug);
  if (!it) {
    return json({ ok: false, error: "slug not found" }, 400, origin);
  }

  const st = normalizeDraftStatus(it.status);
  if (st === "published") {
    return json({ ok: false, error: "already published" }, 400, origin);
  }

  it.status = "approved";
  if (typeof doc.version !== "number" || !Number.isFinite(doc.version)) doc.version = 1;
  else doc.version += 1;

  await writeDraftsDoc(env, doc);
  return json({ ok: true }, 200, origin);
}
