/**
 * GET /api/draft?slug= — one draft item + server-rendered body HTML for admin preview.
 */
import { readDraftsDoc } from "./_lib/drafts-kv.js";
import { normSlug, bodyMarkdownToHtml } from "./_lib/blog-article-html.js";

function json(data, status, origin) {
  const o = origin || "*";
  return new Response(JSON.stringify(data), {
    status: status || 200,
    headers: {
      "Content-Type": "application/json",
      "Access-Control-Allow-Origin": o,
      "Access-Control-Allow-Methods": "GET, OPTIONS",
      "Access-Control-Allow-Headers": "Content-Type"
    }
  });
}

export async function onRequestOptions(context) {
  const origin = context.request.headers.get("Origin") || "*";
  return new Response(null, {
    status: 204,
    headers: {
      "Access-Control-Allow-Origin": origin,
      "Access-Control-Allow-Methods": "GET, OPTIONS",
      "Access-Control-Allow-Headers": "Content-Type"
    }
  });
}

export async function onRequestGet(context) {
  const { request, env } = context;
  const origin = request.headers.get("Origin") || "*";

  if (!env.SEO_KV) {
    return json({ ok: false, error: "kv_not_configured" }, 503, origin);
  }

  const url = new URL(request.url);
  const slug = normSlug({ slug: url.searchParams.get("slug") || "" });
  if (!slug) {
    return json({ ok: false, error: "slug required" }, 400, origin);
  }

  const doc = await readDraftsDoc(env, request);
  if (!Array.isArray(doc.items)) doc.items = [];

  const item = doc.items.find((i) => i && normSlug(i) === slug);
  if (!item) {
    return json({ ok: false, error: "slug not found" }, 404, origin);
  }

  const bodyHtml = bodyMarkdownToHtml(item.body_markdown || "");
  return json({ ok: true, item, bodyHtml }, 200, origin);
}
